import { createAuthPlugin } from "@better-auth-ui/core"
import {
  magicLinkPlugin as coreMagicLinkPlugin,
  type MagicLinkPluginOptions
} from "@better-auth-ui/core/plugins"

import { MagicLink } from "@/components/auth/magic-link"
import { MagicLinkButton } from "@/components/auth/magic-link-button"

export const magicLinkPlugin = createAuthPlugin(
  coreMagicLinkPlugin.id,
  (options: MagicLinkPluginOptions = {}) => ({
    ...coreMagicLinkPlugin(options),
    authButtons: [MagicLinkButton],
    views: {
      auth: { magicLink: MagicLink }
    },
    fallbackViews: {
      auth: { signIn: MagicLink }
    }
  })
)

import {
  type MagicLinkAuthClient,
  signInMagicLinkOptions,
  useAuth
} from "@better-auth-ui/solid"
import { createMutation } from "@tanstack/solid-query"
import { Link } from "@tanstack/solid-router"
import { createSignal, Show } from "solid-js"
import { toast } from "solid-sonner"
import {
  ProviderButtons,
  type SocialLayout
} from "@/components/auth/provider-buttons"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { cn } from "@/lib/utils"

export type MagicLinkProps = {
  className?: string
  socialLayout?: SocialLayout
  socialPosition?: "bottom" | "top"
}

export function MagicLink(props: MagicLinkProps) {
  const auth = useAuth()
  const [email, setEmail] = createSignal("")
  const [emailError, setEmailError] = createSignal<string>()
  const magicLinkLocalization = () =>
    (auth.plugins.find((plugin) => plugin.id === "magicLink")?.localization as
      | { magicLinkSent?: string; sendMagicLink?: string }
      | undefined) ?? {}
  const signInMagicLink = createMutation(() => ({
    ...signInMagicLinkOptions(auth.authClient as MagicLinkAuthClient),
    onSuccess: () => {
      setEmail("")
      toast.success(magicLinkLocalization().magicLinkSent ?? "Magic link sent")
    }
  }))
  const showSeparator = () => Boolean(auth.socialProviders?.length)
  const socialPosition = () => props.socialPosition ?? "bottom"

  const submitMagicLink = (event: SubmitEvent) => {
    event.preventDefault()
    signInMagicLink.mutate({
      callbackURL: `${auth.baseURL}${auth.redirectTo}`,
      email: email()
    } as Parameters<typeof signInMagicLink.mutate>[0])
  }
  return (
    <Card class={cn("w-full max-w-sm", props.className)}>
      <CardHeader>
        <CardTitle class="text-xl font-semibold">
          {auth.localization.auth.signIn}
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div class="flex flex-col gap-6">
          <Show
            when={socialPosition() === "top" && auth.socialProviders?.length}
          >
            <ProviderButtons socialLayout={props.socialLayout} />
            <Show when={showSeparator()}>
              <div class="text-center text-muted-foreground text-xs">
                {auth.localization.auth.or}
              </div>
            </Show>
          </Show>
          <form aria-label="Magic link" onSubmit={submitMagicLink}>
            <div class="grid gap-3">
              <Label for="magic-link-email">
                {auth.localization.auth.email}
              </Label>
              <Input
                aria-invalid={Boolean(emailError())}
                autocomplete="email"
                disabled={signInMagicLink.isPending}
                id="magic-link-email"
                name="email"
                onInput={(event) => {
                  setEmail(event.currentTarget.value)
                  setEmailError(undefined)
                }}
                onInvalid={(event) => {
                  event.preventDefault()
                  setEmailError(event.currentTarget.validationMessage)
                }}
                placeholder={auth.localization.auth.emailPlaceholder}
                required
                type="email"
                value={email()}
              />
              <Show when={emailError()}>
                {(message) => <p role="alert">{message()}</p>}
              </Show>
              <Button disabled={signInMagicLink.isPending} type="submit">
                {magicLinkLocalization().sendMagicLink ?? "Send magic link"}
              </Button>
            </div>
          </form>
          <Show
            when={socialPosition() === "bottom" && auth.socialProviders?.length}
          >
            <Show when={showSeparator()}>
              <div class="text-center text-muted-foreground text-xs">
                {auth.localization.auth.or}
              </div>
            </Show>
            <ProviderButtons socialLayout={props.socialLayout} />
          </Show>
        </div>
        <Show when={auth.emailAndPassword?.enabled}>
          <p class="mt-4 text-center text-muted-foreground text-sm">
            {auth.localization.auth.needToCreateAnAccount}{" "}
            <Link
              params={{ path: auth.viewPaths.auth.signUp }}
              to="/auth/$path"
            >
              {auth.localization.auth.signUp}
            </Link>
          </p>
        </Show>
      </CardContent>
    </Card>
  )
}

import type { AuthView } from "@better-auth-ui/core"
import { useAuth } from "@better-auth-ui/solid"
import { Link } from "@tanstack/solid-router"
import { Lock, Mail } from "lucide-solid"
import { buttonVariants } from "@/components/ui/button"
import { cn } from "@/lib/utils"

export type MagicLinkButtonProps = {
  view?: AuthView
}

export function MagicLinkButton(props: MagicLinkButtonProps) {
  const auth = useAuth()
  const magicLinkView =
    (
      auth.plugins.find((plugin) => plugin.id === "magicLink")?.viewPaths as
        | { auth?: { magicLink?: string } }
        | undefined
    )?.auth?.magicLink ?? "magic-link"
  const isMagicLinkView = () => props.view === "magicLink"

  if (isMagicLinkView() && !auth.emailAndPassword?.enabled) return null

  return (
    <Link
      class={cn(buttonVariants({ variant: "outline" }), "w-full")}
      params={{
        path: isMagicLinkView() ? auth.viewPaths.auth.signIn : magicLinkView
      }}
      to="/auth/$path"
    >
      {isMagicLinkView() ? <Lock /> : <Mail />}
      {auth.localization.auth.continueWith.replace(
        "{{provider}}",
        isMagicLinkView() ? auth.localization.auth.password : "Magic Link"
      )}
    </Link>
  )
}

import { type ButtonRootProps, Root } from "@kobalte/core/button"
import type { PolymorphicProps } from "@kobalte/core/polymorphic"
import { cva, type VariantProps } from "class-variance-authority"
import { type ComponentProps, splitProps, type ValidComponent } from "solid-js"
import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "group/button z-button inline-flex shrink-0 select-none items-center justify-center whitespace-nowrap outline-none transition-all active:not-aria-[haspopup]:translate-y-px disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "z-button-variant-default",
        outline: "z-button-variant-outline",
        secondary: "z-button-variant-secondary",
        ghost: "z-button-variant-ghost",
        destructive: "z-button-variant-destructive",
        link: "z-button-variant-link"
      },
      size: {
        default: "z-button-size-default",
        xs: "z-button-size-xs",
        sm: "z-button-size-sm",
        lg: "z-button-size-lg",
        icon: "z-button-size-icon",
        "icon-xs": "z-button-size-icon-xs",
        "icon-sm": "z-button-size-icon-sm",
        "icon-lg": "z-button-size-icon-lg"
      }
    },
    defaultVariants: {
      variant: "default",
      size: "default"
    }
  }
)

type ButtonProps<T extends ValidComponent = "button"> = PolymorphicProps<
  T,
  ButtonRootProps<T>
> &
  VariantProps<typeof buttonVariants> &
  Pick<ComponentProps<T>, "class">

const Button = <T extends ValidComponent = "button">(props: ButtonProps<T>) => {
  const [local, others] = splitProps(props as ButtonProps, [
    "variant",
    "size",
    "class"
  ])

  return (
    <Root
      class={cn(
        buttonVariants({ variant: local.variant, size: local.size }),
        local.class
      )}
      data-slot="button"
      {...others}
    />
  )
}

export { Button, type ButtonProps, buttonVariants }

